import os
import requests
from bs4 import BeautifulSoup
from urllib.parse import urljoin

def save_wechat_article_full(url):
    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/58.0.3029.110 Safari/537.3',
    }

    try:
        # Create folders
        article_folder = os.path.join('wechat_articles', url.split('/')[-1])
        os.makedirs(article_folder, exist_ok=True)
        img_folder = os.path.join(article_folder, 'images')
        os.makedirs(img_folder, exist_ok=True)

        # Fetch article
        response = requests.get(url, headers=headers, timeout=20)
        response.raise_for_status()

        soup = BeautifulSoup(response.text, 'html.parser')
        title = soup.find('h1', class_='rich_media_title').get_text(strip=True)
        content_div = soup.find('div', class_='rich_media_content')

        # Process all links
        for a_tag in content_div.find_all('a'):
            href = a_tag.get('href')
            if href and not href.startswith(('http', '#')):
                a_tag['href'] = urljoin(url, href)
            # Preserve WeChat's special link styles
            if 'weui-btn' in a_tag.get('class', []):
                a_tag['class'].append('wechat-link')

        # Download and replace images (same as before)
        # ... [keep the existing image handling code] ...

        # WeChat-style CSS
        wechat_css = """
        body {
            font-family: -apple-system-font, BlinkMacSystemFont, "Helvetica Neue", "PingFang SC", "Hiragino Sans GB", 
                         "Microsoft YaHei UI", "Microsoft YaHei", Arial, sans-serif;
            line-height: 1.6;
            color: #333;
            padding: 15px;
        }

        h1 {
            font-size: 22px;
            font-weight: 700;
            margin: 24px 0;
            line-height: 1.4;
            text-align: center;
        }

        h2 {
            font-size: 18px;
            font-weight: 600;
            margin: 20px 0 15px;
            padding-left: 10px;
            border-left: 3px solid #007fff;
            color: #2c3e50;
        }

        h3 {
            font-size: 16px;
            font-weight: 500;
            margin: 18px 0 12px;
            color: #34495e;
            position: relative;
            padding-left: 8px;
        }

        h3::before {
            content: "•";
            color: #007fff;
            position: absolute;
            left: 0;
            top: -1px;
        }

